import { neon } from "@neondatabase/serverless";
import { Pool } from "pg";

type ProjectStatus = string;

type CacheEntry = {
  active: boolean;
  expiresAtMs: number;
};

export type ProjectCacheOptions = {
  ttlMs?: number;
  now?: () => number;
  queryStatus: (projectId: string) => Promise<ProjectStatus | null>;
};

export function createProjectCache({ ttlMs = 30_000, now = Date.now, queryStatus }: ProjectCacheOptions) {
  const cache = new Map<string, CacheEntry>();

  async function isProjectActive(projectId: string): Promise<boolean> {
    const cached = cache.get(projectId);
    const nowMs = now();

    if (cached && cached.expiresAtMs > nowMs) return cached.active;
    cache.delete(projectId);

    const status = await queryStatus(projectId);
    const active = status === "active";
    cache.set(projectId, { active, expiresAtMs: nowMs + ttlMs });
    return active;
  }

  return { isProjectActive } as const;
}

export function createProjectCacheFromEnv(options?: { ttlMs?: number; now?: () => number }) {
  const databaseUrl = process.env.DATABASE_URL;
  if (typeof databaseUrl !== "string" || databaseUrl.length === 0) {
    throw new Error("Missing required environment variable: DATABASE_URL");
  }

  const url = new URL(databaseUrl);
  const isLocal = url.hostname === "localhost" || url.hostname === "127.0.0.1";
  const sql = isLocal ? null : neon(databaseUrl);
  const pool = isLocal ? new Pool({ connectionString: databaseUrl }) : null;

  return createProjectCache({
    ttlMs: options?.ttlMs,
    now: options?.now,
    queryStatus: async (projectId) => {
      if (sql) {
        const rows = (await sql`SELECT status FROM projects WHERE id = ${projectId} LIMIT 1`) as Array<{
          status?: string;
        }>;
        return rows[0]?.status ?? null;
      }

      if (!pool) return null;
      const result = await pool.query<{ status?: string }>("SELECT status FROM projects WHERE id = $1 LIMIT 1", [
        projectId,
      ]);
      return result.rows[0]?.status ?? null;
    },
  });
}

type RetryConfig = {
  maxAttempts: number;
  baseDelayMs: number;
};

export type TinybirdClientConfig = {
  apiUrl: string;
  token: string;
  datasource: string;
  fetch?: typeof fetch;
  retry?: RetryConfig;
  wait?: boolean;
};

export type TinybirdClient = {
  appendEvents: (events: unknown[]) => Promise<void>;
};

function readRequiredEnv(name: string): string {
  const value = process.env[name];
  if (typeof value === "string" && value.length > 0) return value;
  throw new Error(`Missing required environment variable: ${name}`);
}

function buildEventsUrl(apiUrl: string, datasource: string, wait: boolean): string {
  const url = new URL("/v0/events", apiUrl);
  url.searchParams.set("name", datasource);
  url.searchParams.set("wait", wait ? "true" : "false");
  return url.toString();
}

function toNdjson(events: unknown[]): string {
  return `${events.map((e) => JSON.stringify(e)).join("\n")}\n`;
}

function isRetriableStatus(status: number): boolean {
  return status === 408 || status === 429 || status >= 500;
}

async function sleep(ms: number): Promise<void> {
  if (ms <= 0) return;
  await new Promise((resolve) => setTimeout(resolve, ms));
}

export function createTinybirdClientFromEnv(): TinybirdClient {
  return createTinybirdClient({
    apiUrl: readRequiredEnv("TINYBIRD_API_URL"),
    token: readRequiredEnv("TINYBIRD_EVENTS_TOKEN"),
    datasource: "events",
  });
}

export function createTinybirdClient(config: TinybirdClientConfig): TinybirdClient {
  const fetchImpl = config.fetch ?? fetch;
  const retry: RetryConfig = config.retry ?? { maxAttempts: 3, baseDelayMs: 200 };
  const wait = config.wait ?? true;

  if (!config.apiUrl) throw new Error("Missing Tinybird apiUrl");
  if (!config.token) throw new Error("Missing Tinybird token");
  if (!config.datasource) throw new Error("Missing Tinybird datasource");

  const url = buildEventsUrl(config.apiUrl, config.datasource, wait);

  return {
    async appendEvents(events: unknown[]) {
      if (!Array.isArray(events) || events.length === 0) return;

      const body = toNdjson(events);
      let lastError: unknown;

      for (let attempt = 0; attempt < retry.maxAttempts; attempt++) {
        try {
          const response = await fetchImpl(url, {
            method: "POST",
            headers: {
              Authorization: `Bearer ${config.token}`,
              "Content-Type": "application/x-ndjson",
            },
            body,
          });

          if (response.ok) return;

          const responseText = await response.text().catch(() => "");
          const error = new Error(
            `Tinybird ingestion failed (status=${response.status}): ${responseText || response.statusText}`,
          );

          if (!isRetriableStatus(response.status) || attempt === retry.maxAttempts - 1) {
            throw error;
          }

          lastError = error;
        } catch (error) {
          if (attempt === retry.maxAttempts - 1) throw error;
          lastError = error;
        }

        const delay = retry.baseDelayMs * Math.pow(2, attempt);
        await sleep(delay);
      }

      throw lastError instanceof Error ? lastError : new Error("Tinybird ingestion failed");
    },
  };
}

import React from "react";

type OnboardingProject = {
  status: string;
  prUrl: string | null;
  lastEventAt: string | null;
};

type Step = { id: string; label: string; description: string; done: boolean };

function CheckIcon({ className }: { className?: string }) {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" className={className}>
      <path
        d="M13.333 4L5.999 11.333 2.666 8"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function CircleIcon({ className }: { className?: string }) {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" className={className}>
      <circle cx="8" cy="8" r="6" stroke="currentColor" strokeWidth="1.5" />
    </svg>
  );
}

function buildSteps(project: OnboardingProject): Step[] {
  const prCreated = project.prUrl !== null;
  const prMerged = project.status === "active";
  const deployedAndSendingEvents = project.lastEventAt !== null;

  return [
    {
      id: "pr",
      label: "Review the generated PR",
      description: "Check the analytics integration code",
      done: prCreated,
    },
    {
      id: "merge",
      label: "Merge the PR and deploy",
      description: "Deploy to start collecting events",
      done: prMerged,
    },
    {
      id: "events",
      label: "Confirm events are coming in",
      description: "Visit your site to trigger events",
      done: deployedAndSendingEvents,
    },
  ];
}

export default function OnboardingChecklist({ project }: { project: OnboardingProject }) {
  const steps = buildSteps(project);
  const completedCount = steps.filter((s) => s.done).length;
  const progressPercent = Math.round((completedCount / steps.length) * 100);

  return (
    <section className="rounded-lg border border-warm-200 bg-white p-4 shadow-warm">
      <div className="flex items-center justify-between gap-3">
        <h2 className="font-display text-sm font-semibold text-warm-900">Getting Started</h2>
        <span className="text-xs font-medium text-warm-500">
          {completedCount}/{steps.length} complete
        </span>
      </div>

      {/* Progress Bar */}
      <div className="mt-3 h-1.5 w-full overflow-hidden rounded-full bg-warm-100">
        <div
          className="h-full rounded-full bg-gradient-to-r from-brand-500 to-brand-400 transition-all duration-500"
          style={{ width: `${progressPercent}%` }}
        />
      </div>

      <ul className="mt-4 flex flex-col gap-3">
        {steps.map((step, index) => {
          const isNextStep = !step.done && steps.slice(0, index).every((s) => s.done);

          return (
            <li key={step.id} className="flex items-start gap-3">
              {/* Checkbox */}
              <div
                className={[
                  "mt-0.5 flex h-5 w-5 flex-shrink-0 items-center justify-center rounded-full transition-all duration-300",
                  step.done
                    ? "bg-emerald-500 text-white"
                    : isNextStep
                      ? "border-2 border-brand-300 text-brand-300"
                      : "border border-warm-200 text-warm-200",
                ].join(" ")}
              >
                {step.done ? <CheckIcon className="h-3 w-3" /> : <span className="h-2 w-2" />}
              </div>

              {/* Content */}
              <div className="flex-1 min-w-0">
                <p
                  className={[
                    "text-sm font-medium transition-colors",
                    step.done ? "text-warm-400 line-through" : "text-warm-900",
                  ].join(" ")}
                >
                  {step.label}
                </p>
                <p className="text-xs text-warm-500">{step.description}</p>
              </div>

              {/* Status */}
              {step.done && (
                <span className="flex-shrink-0 rounded-full bg-emerald-50 px-2 py-0.5 text-xs font-medium text-emerald-700">
                  Done
                </span>
              )}
              {isNextStep && (
                <span className="flex-shrink-0 rounded-full bg-brand-50 px-2 py-0.5 text-xs font-medium text-brand-600">
                  Next
                </span>
              )}
            </li>
          );
        })}
      </ul>
    </section>
  );
}

"use client";

import React, { useEffect, useRef, useState } from "react";

export type UserDropdownProps = {
  username: string;
  avatarUrl: string | null;
};

function getInitial(username: string): string {
  const trimmed = username.trim();
  const initial = trimmed[0] ?? "?";
  return initial.toUpperCase();
}

export default function UserDropdown({ username, avatarUrl }: UserDropdownProps) {
  const [open, setOpen] = useState(false);
  const rootRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function onDocumentMouseDown(event: MouseEvent) {
      if (!open) return;
      const target = event.target as Node | null;
      if (!target) return;
      if (rootRef.current && !rootRef.current.contains(target)) {
        setOpen(false);
      }
    }

    function onDocumentTouchStart(event: TouchEvent) {
      if (!open) return;
      const target = event.target as Node | null;
      if (!target) return;
      if (rootRef.current && !rootRef.current.contains(target)) {
        setOpen(false);
      }
    }

    function onDocumentKeyDown(event: KeyboardEvent) {
      if (!open) return;
      if (event.key === "Escape") {
        setOpen(false);
      }
    }

    document.addEventListener("mousedown", onDocumentMouseDown);
    document.addEventListener("touchstart", onDocumentTouchStart);
    document.addEventListener("keydown", onDocumentKeyDown);

    return () => {
      document.removeEventListener("mousedown", onDocumentMouseDown);
      document.removeEventListener("touchstart", onDocumentTouchStart);
      document.removeEventListener("keydown", onDocumentKeyDown);
    };
  }, [open]);

  return (
    <div ref={rootRef} className="relative">
      <button
        type="button"
        data-testid="user-dropdown-trigger"
        aria-haspopup="menu"
        aria-expanded={open}
        onClick={() => setOpen((prev) => !prev)}
        className="group flex items-center gap-2 rounded-lg border border-warm-200 bg-white px-2 py-1.5 text-sm font-medium text-warm-700 shadow-sm transition-all hover:border-warm-300 hover:bg-warm-50 hover:text-warm-900"
      >
        {avatarUrl ? (
          <img src={avatarUrl} alt={`${username} avatar`} className="size-8 rounded-full" />
        ) : (
          <div className="flex size-8 items-center justify-center rounded-full bg-warm-200 text-sm font-semibold text-warm-700">
            {getInitial(username)}
          </div>
        )}
        <span className="hidden max-w-40 truncate sm:inline">{username}</span>
        <svg
          data-testid="user-dropdown-chevron"
          className={`size-4 text-warm-400 transition-transform group-hover:text-warm-600 ${open ? "rotate-180" : ""}`}
          viewBox="0 0 16 16"
          fill="none"
          aria-hidden="true"
        >
          <path d="M4 6l4 4 4-4" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
      </button>

      {open && (
        <div
          data-testid="user-dropdown-menu"
          role="menu"
          className="absolute right-0 z-20 mt-2 w-56 overflow-hidden rounded-xl border border-warm-200 bg-white shadow-warm-lg"
        >
          <div className="border-b border-warm-100 px-4 py-3">
            <div className="text-xs font-medium text-warm-500">Signed in as</div>
            <div className="mt-1 truncate text-sm font-semibold text-warm-900">{username}</div>
          </div>
          <form action="/api/auth/logout" method="post" className="p-2">
            <button
              type="submit"
              className="flex w-full items-center gap-2 rounded-lg px-3 py-2 text-sm font-medium text-warm-700 transition-colors hover:bg-warm-50 hover:text-warm-900"
            >
              <svg className="size-4 text-warm-400" viewBox="0 0 16 16" fill="none" aria-hidden="true">
                <path d="M6 14H3a1 1 0 01-1-1V3a1 1 0 011-1h3M11 11l3-3-3-3M14 8H6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
              Log out
            </button>
          </form>
        </div>
      )}
    </div>
  );
}

import fs from 'node:fs';
import path from 'node:path';

export type Period = '24h' | '7d' | '30d';

type FixtureEvent = {
  [key: string]: unknown;
  project_id: string;
  session_id: string;
  event_type: string;
  timestamp: string;
  url?: string;
  path?: string;
  referrer?: string;
  visitor_id?: string;
  is_returning?: number;
};

type ParsedFixtureEvent = FixtureEvent & {
  timestampMs: number;
};

export type E2EOverviewResponse = {
  period: Period;
  pageViews: { total: number; change: number; timeSeries: Array<{ date: string; count: number }> };
  sessions: { total: number; change: number };
  topPages: Array<{ path: string; views: number; percentage: number }>;
  topReferrers: Array<{ referrer: string; count: number; percentage: number }>;
};

export type E2ESessionsResponse = {
  period: Period;
  totalSessions: number;
  newVisitors: number;
  returningVisitors: number;
  timeSeries: Array<{ date: string; newSessions: number; returningSessions: number }>;
};

export type E2ELiveFeedResponse = {
  events: Array<{
    id: string;
    eventType: string;
    path: string;
    referrer: string | null;
    timestamp: string;
    relativeTime: string;
  }>;
  hasMore: boolean;
};

export function isE2EAnalyticsFixtureMode(): boolean {
  return process.env.E2E_TEST_MODE === '1';
}

function appDirFromCwd(): string {
  return process.cwd().endsWith(`${path.sep}apps${path.sep}web`)
    ? process.cwd()
    : path.join(process.cwd(), 'apps', 'web');
}

function fixtureRoot(): string {
  return process.env.E2E_ANALYTICS_FIXTURE_DIR ?? path.join(appDirFromCwd(), '.e2e-fixtures');
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null;
}

function parseEvent(raw: unknown): ParsedFixtureEvent | null {
  if (!isRecord(raw)) return null;

  const projectId = raw.project_id;
  const sessionId = raw.session_id;
  const eventType = raw.event_type;
  const timestamp = raw.timestamp;

  if (typeof projectId !== 'string' || projectId.length === 0) return null;
  if (typeof sessionId !== 'string' || sessionId.length === 0) return null;
  if (typeof eventType !== 'string' || eventType.length === 0) return null;
  if (typeof timestamp !== 'string' || timestamp.length === 0) return null;

  const timestampMs = Date.parse(timestamp);
  if (!Number.isFinite(timestampMs)) return null;

  return {
    ...raw,
    project_id: projectId,
    session_id: sessionId,
    event_type: eventType,
    timestamp,
    timestampMs,
    url: typeof raw.url === 'string' ? raw.url : undefined,
    path: typeof raw.path === 'string' ? raw.path : undefined,
    referrer: typeof raw.referrer === 'string' ? raw.referrer : undefined,
    visitor_id: typeof raw.visitor_id === 'string' ? raw.visitor_id : undefined,
    is_returning: typeof raw.is_returning === 'number' ? raw.is_returning : undefined,
  };
}

function readFixtureJsonFile(filePath: string): ParsedFixtureEvent[] {
  try {
    const parsed = JSON.parse(fs.readFileSync(filePath, 'utf8')) as unknown;
    if (!isRecord(parsed) || !Array.isArray(parsed.events)) return [];
    return parsed.events.flatMap((event) => {
      const normalized = parseEvent(event);
      return normalized ? [normalized] : [];
    });
  } catch {
    return [];
  }
}

function readFixtureJsonlFile(filePath: string): ParsedFixtureEvent[] {
  try {
    return fs
      .readFileSync(filePath, 'utf8')
      .split(/\r?\n/)
      .flatMap((line) => {
        const trimmed = line.trim();
        if (!trimmed) return [];

        try {
          const normalized = parseEvent(JSON.parse(trimmed) as unknown);
          return normalized ? [normalized] : [];
        } catch {
          return [];
        }
      });
  } catch {
    return [];
  }
}

export function loadE2EAnalyticsEvents(projectId: string): ParsedFixtureEvent[] {
  const root = fixtureRoot();
  if (!fs.existsSync(root)) return [];

  const events: ParsedFixtureEvent[] = [];
  for (const entry of fs.readdirSync(root, { withFileTypes: true })) {
    if (!entry.isDirectory()) continue;
    const jsonPath = path.join(root, entry.name, 'events.json');
    const jsonlPath = path.join(root, entry.name, 'events.jsonl');
    if (fs.existsSync(jsonPath)) events.push(...readFixtureJsonFile(jsonPath));
    if (fs.existsSync(jsonlPath)) events.push(...readFixtureJsonlFile(jsonlPath));
  }

  return events
    .filter((event) => event.project_id === projectId)
    .sort((a, b) => a.timestampMs - b.timestampMs);
}

function periodMs(period: Period): number {
  switch (period) {
    case '24h':
      return 24 * 60 * 60 * 1000;
    case '7d':
      return 7 * 24 * 60 * 60 * 1000;
    case '30d':
      return 30 * 24 * 60 * 60 * 1000;
  }
}

function fixtureNow(events: ParsedFixtureEvent[]): number {
  const explicit = process.env.E2E_ANALYTICS_NOW;
  if (explicit) {
    const parsed = Date.parse(explicit);
    if (Number.isFinite(parsed)) return parsed;
  }

  const max = Math.max(...events.map((event) => event.timestampMs), Number.NEGATIVE_INFINITY);
  return Number.isFinite(max) ? max + 1 : Date.now();
}

function eventsInWindow(
  events: ParsedFixtureEvent[],
  startMs: number,
  endMs: number
): ParsedFixtureEvent[] {
  return events.filter((event) => event.timestampMs >= startMs && event.timestampMs < endMs);
}

function dateKey(timestampMs: number): string {
  return new Date(timestampMs).toISOString().slice(0, 10);
}

function groupCountsByDate(events: ParsedFixtureEvent[]): Array<{ date: string; count: number }> {
  const counts = new Map<string, number>();
  for (const event of events) {
    const date = dateKey(event.timestampMs);
    counts.set(date, (counts.get(date) ?? 0) + 1);
  }
  return Array.from(counts.entries())
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([date, count]) => ({ date, count }));
}

function percentChange(current: number, previous: number): number {
  if (previous === 0) return current === 0 ? 0 : 100;
  return Math.round(((current - previous) / previous) * 100);
}

function roundedPercentage(count: number, total: number): number {
  if (total === 0) return 0;
  return Math.round((count * 10000) / total) / 100;
}

function topCounts(
  events: ParsedFixtureEvent[],
  valueForEvent: (event: ParsedFixtureEvent) => string
): Array<{ label: string; count: number; percentage: number }> {
  const counts = new Map<string, number>();
  for (const event of events) {
    const label = valueForEvent(event);
    counts.set(label, (counts.get(label) ?? 0) + 1);
  }

  return Array.from(counts.entries())
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
    .slice(0, 10)
    .map(([label, count]) => ({
      label,
      count,
      percentage: roundedPercentage(count, events.length),
    }));
}

function referrerHost(referrer: string | undefined): string {
  if (!referrer) return 'Direct';
  try {
    return new URL(referrer).hostname || 'Direct';
  } catch {
    return referrer || 'Direct';
  }
}

export function buildE2EOverview(projectId: string, period: Period): E2EOverviewResponse {
  const events = loadE2EAnalyticsEvents(projectId);
  const now = fixtureNow(events);
  const duration = periodMs(period);
  const start = now - duration;
  const previousStart = start - duration;

  const currentEvents = eventsInWindow(events, start, now);
  const previousEvents = eventsInWindow(events, previousStart, start);

  const currentPageViews = currentEvents.filter((event) => event.event_type === 'page_view');
  const previousPageViews = previousEvents.filter((event) => event.event_type === 'page_view');
  const currentSessions = currentEvents.filter((event) => event.event_type === 'session_start');
  const previousSessions = previousEvents.filter((event) => event.event_type === 'session_start');

  const topPages = topCounts(currentPageViews, (event) => event.path ?? '').map((item) => ({
    path: item.label,
    views: item.count,
    percentage: item.percentage,
  }));

  const topReferrers = topCounts(currentPageViews, (event) => referrerHost(event.referrer)).map(
    (item) => ({
      referrer: item.label,
      count: item.count,
      percentage: item.percentage,
    })
  );

  return {
    period,
    pageViews: {
      total: currentPageViews.length,
      change: percentChange(currentPageViews.length, previousPageViews.length),
      timeSeries: groupCountsByDate(currentPageViews),
    },
    sessions: {
      total: currentSessions.length,
      change: percentChange(currentSessions.length, previousSessions.length),
    },
    topPages,
    topReferrers,
  };
}

export function buildE2ESessions(projectId: string, period: Period): E2ESessionsResponse {
  const events = loadE2EAnalyticsEvents(projectId);
  const now = fixtureNow(events);
  const start = now - periodMs(period);
  const sessions = eventsInWindow(events, start, now).filter(
    (event) => event.event_type === 'session_start'
  );

  const byDate = new Map<string, { newSessions: number; returningSessions: number }>();
  let newVisitors = 0;
  let returningVisitors = 0;

  for (const event of sessions) {
    const date = dateKey(event.timestampMs);
    const bucket = byDate.get(date) ?? { newSessions: 0, returningSessions: 0 };
    if (event.is_returning === 1) {
      bucket.returningSessions += 1;
      returningVisitors += 1;
    } else {
      bucket.newSessions += 1;
      newVisitors += 1;
    }
    byDate.set(date, bucket);
  }

  const timeSeries = Array.from(byDate.entries())
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([date, counts]) => ({ date, ...counts }));

  return {
    period,
    totalSessions: sessions.length,
    newVisitors,
    returningVisitors,
    timeSeries,
  };
}

function relativeTime(fromMs: number, toMs: number): string {
  const seconds = Math.max(0, Math.round((toMs - fromMs) / 1000));
  if (seconds < 60) return `${seconds} seconds ago`;
  const minutes = Math.round(seconds / 60);
  if (minutes < 60) return `${minutes} minutes ago`;
  const hours = Math.round(minutes / 60);
  if (hours < 24) return `${hours} hours ago`;
  const days = Math.round(hours / 24);
  return `${days} days ago`;
}

export function buildE2ELiveFeed(params: {
  projectId: string;
  limit: number;
  since?: Date | null;
}): E2ELiveFeedResponse {
  const events = loadE2EAnalyticsEvents(params.projectId);
  const now = fixtureNow(events);
  const sinceMs =
    params.since && !Number.isNaN(params.since.getTime())
      ? params.since.getTime()
      : Date.parse('2024-01-01T00:00:00.000Z');

  const limited = events
    .filter((event) => event.timestampMs > sinceMs)
    .sort((a, b) => b.timestampMs - a.timestampMs)
    .slice(0, params.limit);

  return {
    events: limited.map((event, index) => ({
      id: `${event.timestamp}-${index}`,
      eventType: event.event_type,
      path: event.path ?? '',
      referrer: event.referrer && event.referrer.length > 0 ? event.referrer : null,
      timestamp: event.timestamp,
      relativeTime: relativeTime(event.timestampMs, now),
    })),
    hasMore: limited.length >= params.limit,
  };
}

import { and, eq } from "drizzle-orm";

import { getInstallationAccessToken, type GitHubInstallationAccessToken } from "../../github/app";
import { db } from "../client";
import { githubTokens } from "../schema";

export type UpsertInstallationTokenParams = {
  userId: string;
  installationId: bigint;
  token: string;
  expiresAt: Date;
};

export async function upsertInstallationLink(params: { userId: string; installationId: bigint }): Promise<void> {
  await db
    .insert(githubTokens)
    .values({ userId: params.userId, installationId: params.installationId })
    .onConflictDoUpdate({
      target: githubTokens.installationId,
      set: { userId: params.userId },
    });
}

export async function upsertInstallationToken(params: UpsertInstallationTokenParams): Promise<void> {
  await db
    .insert(githubTokens)
    .values({
      userId: params.userId,
      installationId: params.installationId,
      installationAccessToken: params.token,
      installationTokenExpiresAt: params.expiresAt,
    })
    .onConflictDoUpdate({
      target: githubTokens.installationId,
      set: {
        userId: params.userId,
        installationAccessToken: params.token,
        installationTokenExpiresAt: params.expiresAt,
      },
    });
}

export type StoredInstallationToken = {
  token: string;
  expiresAt: Date;
};

export async function getStoredInstallationToken(params: {
  userId: string;
  installationId: bigint;
  now?: Date;
}): Promise<StoredInstallationToken | null> {
  const now = params.now ?? new Date();

  const rows = await db
    .select({
      token: githubTokens.installationAccessToken,
      expiresAt: githubTokens.installationTokenExpiresAt,
    })
    .from(githubTokens)
    .where(and(eq(githubTokens.userId, params.userId), eq(githubTokens.installationId, params.installationId)));

  const row = rows[0];
  if (!row?.token || !row.expiresAt) return null;
  if (row.expiresAt.getTime() <= now.getTime()) return null;

  return { token: row.token, expiresAt: row.expiresAt };
}

function toSafeNumber(value: bigint): number {
  const asNumber = Number(value);
  if (!Number.isSafeInteger(asNumber)) {
    throw new Error(`Installation ID is too large to safely convert to number: ${value.toString()}`);
  }
  return asNumber;
}

export type RefreshInstallationAccessTokenFn = (installationId: number) => Promise<GitHubInstallationAccessToken>;

export async function getOrRefreshInstallationToken(params: {
  userId: string;
  installationId: bigint;
  now?: Date;
  refreshInstallationAccessToken?: RefreshInstallationAccessTokenFn;
}): Promise<StoredInstallationToken> {
  const now = params.now ?? new Date();
  const existing = await getStoredInstallationToken({ userId: params.userId, installationId: params.installationId, now });
  if (existing) return existing;

  const refresh = params.refreshInstallationAccessToken ?? getInstallationAccessToken;
  const installationId = toSafeNumber(params.installationId);
  const refreshed = await refresh(installationId);

  const expiresAt = new Date(refreshed.expiresAt);
  if (Number.isNaN(expiresAt.getTime())) {
    throw new Error(`Invalid refreshed installation token expiry: ${JSON.stringify(refreshed.expiresAt)}`);
  }

  await upsertInstallationToken({
    userId: params.userId,
    installationId: params.installationId,
    token: refreshed.token,
    expiresAt,
  });

  return { token: refreshed.token, expiresAt };
}

import { App } from "@octokit/app";
import { Octokit } from "@octokit/rest";

export type GitHubAuth =
  | { type: "app" }
  | {
      type: "installation";
      installationId: number;
    };

export type GitHubAuthResponse =
  | { token: string }
  | {
      token: string;
      expiresAt: string;
    };

export type GitHubAuthFn = (auth: GitHubAuth) => Promise<GitHubAuthResponse>;

export type GitHubInstallationAccessToken = {
  token: string;
  expiresAt: string;
};

export type CreateOctokitFn<TOctokit = Octokit> = (options: { auth: string }) => TOctokit;

export type GitHubAppClient<TOctokit = Octokit> = {
  getAppJwt: () => Promise<string>;
  getInstallationAccessToken: (installationId: number) => Promise<GitHubInstallationAccessToken>;
  getInstallationOctokit: (installationId: number) => Promise<TOctokit>;
};

const INSTALLATION_TOKEN_REFRESH_SKEW_MS = 60_000;

function readRequiredEnv(name: string): string {
  const value = process.env[name];
  if (typeof value === "string" && value.length > 0) return value;

  throw new Error(
    `Missing required environment variable: ${name}. Set it in apps/web/.env.local for local dev, or in your Vercel project environment variables.`,
  );
}

function readGitHubAppConfigFromEnv(): { appId: number; privateKey: string } {
  const appIdRaw = readRequiredEnv("GITHUB_APP_ID");
  const appId = Number(appIdRaw);
  if (!Number.isFinite(appId) || appId <= 0) {
    throw new Error(`Invalid GITHUB_APP_ID: expected a positive number, got ${JSON.stringify(appIdRaw)}`);
  }

  const privateKey = readRequiredEnv("GITHUB_APP_PRIVATE_KEY").replaceAll("\\n", "\n");
  return { appId, privateKey };
}

function createDefaultAuth(appId: number, privateKey: string): GitHubAuthFn {
  const app = new App({ appId, privateKey, Octokit });
  return (auth) => app.octokit.auth(auth as never) as Promise<GitHubAuthResponse>;
}

export function createGitHubAppClient<TOctokit = Octokit>(options: {
  appId: number;
  privateKey: string;
  auth?: GitHubAuthFn;
  now?: () => number;
  createOctokit?: CreateOctokitFn<TOctokit>;
}): GitHubAppClient<TOctokit> {
  const auth = options.auth ?? createDefaultAuth(options.appId, options.privateKey);
  const now = options.now ?? (() => Date.now());
  const createOctokit: CreateOctokitFn<TOctokit> = options.createOctokit ?? ((o) => new Octokit(o) as never);

  const installationTokenCache = new Map<number, GitHubInstallationAccessToken & { expiresAtMs: number }>();

  async function getAppJwt(): Promise<string> {
    const result = await auth({ type: "app" });
    return result.token;
  }

  async function getInstallationAccessToken(installationId: number): Promise<GitHubInstallationAccessToken> {
    const cached = installationTokenCache.get(installationId);
    if (cached && cached.expiresAtMs - now() >= INSTALLATION_TOKEN_REFRESH_SKEW_MS) {
      return { token: cached.token, expiresAt: cached.expiresAt };
    }

    const result = await auth({ type: "installation", installationId });
    if (!("expiresAt" in result)) {
      throw new Error("Invalid GitHub installation auth response: missing expiresAt");
    }

    const expiresAtMs = Date.parse(result.expiresAt);
    if (!Number.isFinite(expiresAtMs)) {
      throw new Error(`Invalid GitHub installation auth response: invalid expiresAt ${JSON.stringify(result.expiresAt)}`);
    }

    const token = { token: result.token, expiresAt: result.expiresAt, expiresAtMs };
    installationTokenCache.set(installationId, token);
    return { token: token.token, expiresAt: token.expiresAt };
  }

  async function getInstallationOctokit(installationId: number): Promise<TOctokit> {
    const { token } = await getInstallationAccessToken(installationId);
    return createOctokit({ auth: token });
  }

  return { getAppJwt, getInstallationAccessToken, getInstallationOctokit };
}

let singleton: GitHubAppClient | null = null;

function getSingleton(): GitHubAppClient {
  if (singleton) return singleton;
  const { appId, privateKey } = readGitHubAppConfigFromEnv();
  singleton = createGitHubAppClient({ appId, privateKey });
  return singleton;
}

export function __testOnly_clearGitHubAppClient(): void {
  singleton = null;
}

export async function getAppJwt(): Promise<string> {
  return getSingleton().getAppJwt();
}

export async function getInstallationAccessToken(installationId: number): Promise<GitHubInstallationAccessToken> {
  return getSingleton().getInstallationAccessToken(installationId);
}

export async function getInstallationOctokit(installationId: number): Promise<Octokit> {
  return getSingleton().getInstallationOctokit(installationId);
}

type GitHubContentFile = {
  type: "file";
  encoding?: string;
  content?: string;
};

type GitHubContentResponse = { data: GitHubContentFile | { type: string } | unknown };

export type OctokitLike = {
  repos: {
    getContent: (params: { owner: string; repo: string; path: string; ref?: string }) => Promise<GitHubContentResponse>;
  };
};

export type PackageJson = {
  dependencies?: Record<string, string>;
  devDependencies?: Record<string, string>;
  workspaces?: unknown;
};

export type PackageJsonAnalysis = {
  nextVersion: string | null;
  existingAnalytics: string[];
  hasWorkspaces: boolean;
};

export type DetectedFramework = "nextjs-app" | "nextjs-pages" | null;

export type RouterDetectionResult = {
  framework: DetectedFramework;
  entryPoint: string | null;
};

const ANALYTICS_PACKAGES = [
  "posthog-js",
  "posthog-node",
  "@amplitude/analytics-browser",
  "mixpanel-browser",
  "@segment/analytics-next",
  "@vercel/analytics",
  "plausible-tracker",
  "@google-analytics/data",
  "ga-4-react",
] as const;

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isNotFoundError(error: unknown): boolean {
  return isRecord(error) && error.status === 404;
}

function decodeGitHubFileContent(file: GitHubContentFile): string | null {
  if (!file.content) return null;
  if (!file.encoding || file.encoding === "base64") {
    return Buffer.from(file.content, "base64").toString("utf8");
  }
  return null;
}

async function fetchTextFileIfExists(
  octokit: OctokitLike,
  owner: string,
  repo: string,
  path: string,
  options?: { ref?: string },
): Promise<string | null> {
  try {
    const response = await octokit.repos.getContent({ owner, repo, path, ref: options?.ref });
    const data = response.data;
    if (!isRecord(data) || data.type !== "file") return null;
    return decodeGitHubFileContent(data as GitHubContentFile);
  } catch (error) {
    if (isNotFoundError(error)) return null;
    throw error;
  }
}

export async function fetchPackageJson(
  octokit: OctokitLike,
  owner: string,
  repo: string,
  options?: { ref?: string },
): Promise<PackageJson | null> {
  try {
    const response = await octokit.repos.getContent({ owner, repo, path: "package.json", ref: options?.ref });
    const data = response.data;
    if (!isRecord(data) || data.type !== "file") return null;
    const content = decodeGitHubFileContent(data as GitHubContentFile);
    if (!content) return null;
    return JSON.parse(content) as PackageJson;
  } catch (error) {
    if (isNotFoundError(error)) return null;
    throw error;
  }
}

export function analyzePackageJson(packageJson: PackageJson): PackageJsonAnalysis {
  const dependencies = packageJson.dependencies ?? {};
  const devDependencies = packageJson.devDependencies ?? {};
  const allDeps = { ...dependencies, ...devDependencies };

  const nextVersion = typeof allDeps.next === "string" ? allDeps.next : null;
  const existingAnalytics = ANALYTICS_PACKAGES.filter((name) => typeof allDeps[name] === "string");
  const hasWorkspaces = Array.isArray(packageJson.workspaces) || (isRecord(packageJson.workspaces) && packageJson.workspaces);

  return { nextVersion, existingAnalytics: [...existingAnalytics], hasWorkspaces: Boolean(hasWorkspaces) };
}

export async function fileExists(
  octokit: OctokitLike,
  owner: string,
  repo: string,
  path: string,
  options?: { ref?: string },
): Promise<boolean> {
  try {
    const response = await octokit.repos.getContent({ owner, repo, path, ref: options?.ref });
    const data = response.data;
    return isRecord(data) && data.type === "file";
  } catch (error) {
    if (isNotFoundError(error)) return false;
    throw error;
  }
}

export async function findFirstExistingPath(
  octokit: OctokitLike,
  owner: string,
  repo: string,
  paths: string[],
  options?: { ref?: string },
): Promise<string | null> {
  for (const path of paths) {
    if (await fileExists(octokit, owner, repo, path, options)) return path;
  }
  return null;
}

const APP_ROUTER_ENTRYPOINT_CANDIDATES = [
  "app/layout.tsx",
  "app/layout.jsx",
  "app/layout.js",
  "src/app/layout.tsx",
  "src/app/layout.jsx",
  "src/app/layout.js",
];

const PAGES_ROUTER_ENTRYPOINT_CANDIDATES = [
  "pages/_app.tsx",
  "pages/_app.jsx",
  "pages/_app.js",
  "src/pages/_app.tsx",
  "src/pages/_app.jsx",
  "src/pages/_app.js",
];

const MONOREPO_SENTINELS = ["pnpm-workspace.yaml", "lerna.json"] as const;

function parsePnpmWorkspacePackages(yaml: string): string[] | null {
  const lines = yaml
    .split("\n")
    .map((line) => line.replace(/\r$/, ""))
    .map((line) => line.replace(/#.*$/, "").trimEnd());

  const packagesIndex = lines.findIndex((line) => line.trim() === "packages:");
  if (packagesIndex === -1) return null;

  const result: string[] = [];
  for (let index = packagesIndex + 1; index < lines.length; index += 1) {
    const raw = lines[index];
    if (!raw) continue;

    const trimmed = raw.trim();
    if (!trimmed) continue;
    if (!trimmed.startsWith("-")) {
      // We've exited the list (or hit another section).
      if (result.length > 0) break;
      continue;
    }

    const value = trimmed.replace(/^-+\s*/, "").trim();
    if (value) result.push(value);
  }

  return result.length > 0 ? result : null;
}

export async function detectNextRouter(
  octokit: OctokitLike,
  owner: string,
  repo: string,
  options?: { ref?: string },
): Promise<RouterDetectionResult> {
  const appEntryPoint = await findFirstExistingPath(
    octokit,
    owner,
    repo,
    APP_ROUTER_ENTRYPOINT_CANDIDATES,
    options,
  );
  if (appEntryPoint) return { framework: "nextjs-app", entryPoint: appEntryPoint };

  const pagesEntryPoint = await findFirstExistingPath(
    octokit,
    owner,
    repo,
    PAGES_ROUTER_ENTRYPOINT_CANDIDATES,
    options,
  );
  if (pagesEntryPoint) return { framework: "nextjs-pages", entryPoint: pagesEntryPoint };

  return { framework: null, entryPoint: null };
}

export async function detectMonorepo(
  octokit: OctokitLike,
  owner: string,
  repo: string,
  packageJson: PackageJson,
  options?: { ref?: string },
): Promise<boolean> {
  const analysis = analyzePackageJson(packageJson);
  if (analysis.hasWorkspaces) return true;

  const pnpmWorkspace = await fetchTextFileIfExists(octokit, owner, repo, "pnpm-workspace.yaml", options);
  if (pnpmWorkspace) {
    const packages = parsePnpmWorkspacePackages(pnpmWorkspace);
    // `create-next-app` can generate a workspace file with `packages: ['.']` even for single-package repos.
    // Treat that case as non-monorepo to avoid incorrectly marking such repos as unsupported.
    if (!packages) return true;
    const nonRootPackages = packages.filter((entry) => entry !== "." && entry !== "./");
    if (nonRootPackages.length > 0) return true;
  }

  for (const sentinel of MONOREPO_SENTINELS) {
    if (sentinel === "pnpm-workspace.yaml") continue;
    if (await fileExists(octokit, owner, repo, sentinel, options)) return true;
  }

  return false;
}

import { renderAppRouterAnalyticsComponent } from "./templates/app-router";
import { renderPagesRouterAnalyticsHook } from "./templates/pages-router";
import { hasAtAlias, resolveAnalyticsPaths } from "./templates/paths";
import { insertAnalyticsIntoAppRouterLayout, insertAnalyticsIntoPagesRouterApp } from "./templates/insert-analytics";
import { setProjectPullRequestByRepoId } from "../db/queries/projects";

type OctokitResponse<T> = { data: T };

type RepoResponse = OctokitResponse<{ default_branch: string }>;
type RefResponse = OctokitResponse<{ object: { sha: string } }>;

type ContentResponse = OctokitResponse<unknown>;

export type PrOctokitLike = {
  repos: {
    get: (params: { owner: string; repo: string }) => Promise<RepoResponse>;
    getContent: (params: { owner: string; repo: string; path: string; ref?: string }) => Promise<ContentResponse>;
    createOrUpdateFileContents: (params: {
      owner: string;
      repo: string;
      branch: string;
      path: string;
      message: string;
      content: string;
      sha?: string;
    }) => Promise<unknown>;
  };
  git: {
    getRef: (params: { owner: string; repo: string; ref: string }) => Promise<RefResponse>;
    createRef: (params: { owner: string; repo: string; ref: string; sha: string }) => Promise<unknown>;
  };
};

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isBranchExistsError(error: unknown): boolean {
  return isRecord(error) && error.status === 422;
}

const BRANCH_PREFIX = "add-fast-pr-analytics";

export async function createAnalyticsBranch(
  octokit: PrOctokitLike,
  params: { owner: string; repo: string },
): Promise<string> {
  const { data: repoData } = await octokit.repos.get({ owner: params.owner, repo: params.repo });
  const defaultBranch = repoData.default_branch;

  const { data: ref } = await octokit.git.getRef({
    owner: params.owner,
    repo: params.repo,
    ref: `heads/${defaultBranch}`,
  });
  const baseSha = ref.object.sha;

  for (let suffix = 1; suffix < 1000; suffix += 1) {
    const branchName = suffix === 1 ? BRANCH_PREFIX : `${BRANCH_PREFIX}-${suffix}`;
    try {
      await octokit.git.createRef({
        owner: params.owner,
        repo: params.repo,
        ref: `refs/heads/${branchName}`,
        sha: baseSha,
      });
      return branchName;
    } catch (error) {
      if (isBranchExistsError(error)) continue;
      throw error;
    }
  }

  throw new Error(`Failed to create a unique analytics branch after 999 attempts (prefix: ${BRANCH_PREFIX})`);
}

function isNotFoundError(error: unknown): boolean {
  return isRecord(error) && error.status === 404;
}

async function fetchJsonFileIfExists(
  octokit: PrOctokitLike,
  params: { owner: string; repo: string; path: string; ref?: string },
): Promise<unknown | null> {
  try {
    const response = await octokit.repos.getContent(params);
    const file = response.data;
    if (!isRecord(file) || file.type !== "file" || typeof file.content !== "string") return null;
    const text = Buffer.from(file.content, "base64").toString("utf8");
    return JSON.parse(text) as unknown;
  } catch (error) {
    if (isNotFoundError(error)) return null;
    throw error;
  }
}

async function fetchFileShaIfExists(
  octokit: PrOctokitLike,
  params: { owner: string; repo: string; path: string; ref?: string },
): Promise<string | null> {
  try {
    const response = await octokit.repos.getContent(params);
    const file = response.data;
    if (!isRecord(file) || file.type !== "file") return null;
    return typeof file.sha === "string" && file.sha.length > 0 ? file.sha : null;
  } catch (error) {
    if (isNotFoundError(error)) return null;
    throw error;
  }
}

async function fetchTextFile(
  octokit: PrOctokitLike,
  params: { owner: string; repo: string; path: string; ref?: string },
): Promise<{ sha: string; content: string }> {
  const response = await octokit.repos.getContent(params);
  const file = response.data;
  if (!isRecord(file) || file.type !== "file") {
    throw new Error(`Expected GitHub content at ${params.path} to be a file`);
  }
  if (typeof file.sha !== "string" || file.sha.length === 0) {
    throw new Error(`Expected GitHub content at ${params.path} to include a sha`);
  }
  const content = typeof file.content === "string" ? Buffer.from(file.content, "base64").toString("utf8") : "";
  return { sha: file.sha, content };
}

function encodeBase64(text: string): string {
  return Buffer.from(text, "utf8").toString("base64");
}

export async function commitAnalyticsFiles(
  octokit: PrOctokitLike,
  params: {
    owner: string;
    repo: string;
    branch: string;
    defaultBranch: string;
    projectId: string;
    detection: { framework: "nextjs-app" | "nextjs-pages"; entryPoint: string };
    eventsUrl: string;
  },
): Promise<{ componentFilePath: string }> {
  const tsconfig =
    (await fetchJsonFileIfExists(octokit, {
      owner: params.owner,
      repo: params.repo,
      path: "tsconfig.json",
      ref: params.defaultBranch,
    })) ??
    (await fetchJsonFileIfExists(octokit, {
      owner: params.owner,
      repo: params.repo,
      path: "jsconfig.json",
      ref: params.defaultBranch,
    }));

  const useAtAlias = tsconfig ? hasAtAlias(tsconfig) : false;
  const paths = resolveAnalyticsPaths({ entryPointPath: params.detection.entryPoint, useAtAlias });

  const componentContent =
    params.detection.framework === "nextjs-app"
      ? renderAppRouterAnalyticsComponent({ projectId: params.projectId, eventsUrl: params.eventsUrl })
      : renderPagesRouterAnalyticsHook({ projectId: params.projectId, eventsUrl: params.eventsUrl });

  const existingComponentSha = await fetchFileShaIfExists(octokit, {
    owner: params.owner,
    repo: params.repo,
    path: paths.componentFilePath,
    ref: params.defaultBranch,
  });

  await octokit.repos.createOrUpdateFileContents({
    owner: params.owner,
    repo: params.repo,
    branch: params.branch,
    path: paths.componentFilePath,
    message: `Add Fast PR Analytics component`,
    content: encodeBase64(componentContent),
    ...(existingComponentSha ? { sha: existingComponentSha } : {}),
  });

  const entryPointFile = await fetchTextFile(octokit, {
    owner: params.owner,
    repo: params.repo,
    path: params.detection.entryPoint,
    ref: params.defaultBranch,
  });

  const updatedEntryPointContent =
    params.detection.framework === "nextjs-app"
      ? insertAnalyticsIntoAppRouterLayout({
          content: entryPointFile.content,
          importPath: paths.importPath,
          componentName: "FastPrAnalytics",
        })
      : insertAnalyticsIntoPagesRouterApp({
          content: entryPointFile.content,
          importPath: paths.importPath,
          hookName: "useFastPrAnalytics",
        });

  await octokit.repos.createOrUpdateFileContents({
    owner: params.owner,
    repo: params.repo,
    branch: params.branch,
    path: params.detection.entryPoint,
    message: `Add Fast PR Analytics to ${params.detection.entryPoint}`,
    content: encodeBase64(updatedEntryPointContent),
    sha: entryPointFile.sha,
  });

  return { componentFilePath: paths.componentFilePath };
}

type PullResponse = OctokitResponse<{ number: number; html_url: string }>;
type PullListResponse = OctokitResponse<Array<{ number: number; html_url: string }>>;

export type PullsOctokitLike = {
  pulls: {
    create: (params: {
      owner: string;
      repo: string;
      title: string;
      head: string;
      base: string;
      body: string;
    }) => Promise<PullResponse>;
    list: (params: { owner: string; repo: string; head: string; state: "open" | "closed" | "all" }) => Promise<PullListResponse>;
  };
};

function generatePrBody(params: { projectId: string; entryPoint: string }): string {
  return [
    "This PR adds Fast PR Analytics for automatic page view tracking.",
    "",
    "## Changes",
    `- Added analytics component in \`components/fast-pr-analytics.tsx\``,
    `- Added initialization in \`${params.entryPoint}\``,
    "",
    "## What happens next",
    "1. Review and merge this PR",
    "2. Deploy via your normal process",
    `3. Visit ${process.env.NEXT_PUBLIC_APP_URL ?? "https://app.productname.com"}/projects/${params.projectId} to see your analytics`,
  ].join("\n");
}

export async function openAnalyticsPullRequest(
  octokit: PullsOctokitLike,
  params: {
    repoId: bigint;
    owner: string;
    repo: string;
    branch: string;
    defaultBranch: string;
    projectId: string;
    entryPoint: string;
  },
): Promise<{ prNumber: number; prUrl: string; alreadyExists: boolean }> {
  const title = "Add Fast PR Analytics";
  const body = generatePrBody({ projectId: params.projectId, entryPoint: params.entryPoint });

  try {
    const { data: pr } = await octokit.pulls.create({
      owner: params.owner,
      repo: params.repo,
      title,
      head: params.branch,
      base: params.defaultBranch,
      body,
    });

    await setProjectPullRequestByRepoId({ repoId: params.repoId, prNumber: pr.number, prUrl: pr.html_url });
    return { prNumber: pr.number, prUrl: pr.html_url, alreadyExists: false };
  } catch (error) {
    if (!isBranchExistsError(error)) throw error;

    const { data: prs } = await octokit.pulls.list({
      owner: params.owner,
      repo: params.repo,
      head: `${params.owner}:${params.branch}`,
      state: "open",
    });
    const existing = prs[0];
    if (!existing) throw new Error(`PR already exists for branch ${params.branch}, but no open PR was found`);

    await setProjectPullRequestByRepoId({ repoId: params.repoId, prNumber: existing.number, prUrl: existing.html_url });
    return { prNumber: existing.number, prUrl: existing.html_url, alreadyExists: true };
  }
}

