    });

    env.dispatch("click", { target: regularLink });

    const clicks = tracker.getAndClearClicks();
    expect(clicks).toHaveLength(0);

    tracker.destroy();
  });
});

import { describe, expect, it, vi, beforeEach, afterEach } from "vitest";

import { createEngagementTracker } from "../src/engagement";

function installDocument() {
  const handlers: Map<string, Set<EventListener>> = new Map();

  Object.defineProperty(globalThis, "document", {
    value: {
      visibilityState: "visible",
      addEventListener(type: string, handler: EventListener) {
        if (!handlers.has(type)) handlers.set(type, new Set());
        handlers.get(type)!.add(handler);
      },
      removeEventListener(type: string, handler: EventListener) {
        handlers.get(type)?.delete(handler);
      },
    },
    configurable: true,
  });

  Object.defineProperty(globalThis, "window", {
    value: {
      addEventListener(type: string, handler: EventListener, options?: AddEventListenerOptions | boolean) {
        if (!handlers.has(type)) handlers.set(type, new Set());
        handlers.get(type)!.add(handler);
      },
      removeEventListener(type: string, handler: EventListener) {
        handlers.get(type)?.delete(handler);
      },
    },
    configurable: true,
  });

  return {
    dispatch(type: string, event?: Event) {
      const defaultEvent = { type } as Event;
      handlers.get(type)?.forEach((h) => h(event ?? defaultEvent));
    },
    setVisibilityState(state: "visible" | "hidden") {
      (globalThis.document as any).visibilityState = state;
    },
    getHandlerCount(type: string) {
      return handlers.get(type)?.size ?? 0;
    },
  };
}

describe("Task 1.1.A - Engagement Time Tracker", () => {
  beforeEach(() => {
    vi.useFakeTimers();
    vi.setSystemTime(new Date("2025-01-01T00:00:00.000Z"));
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("createEngagementTracker returns object with getEngagementTimeMs, reset, and destroy methods", () => {
    installDocument();
    const tracker = createEngagementTracker();

    expect(typeof tracker.getEngagementTimeMs).toBe("function");
    expect(typeof tracker.reset).toBe("function");
    expect(typeof tracker.destroy).toBe("function");

    tracker.destroy();
  });

  it("engagement time only accumulates when tab is visible AND user is active", () => {
    const doc = installDocument();
    const tracker = createEngagementTracker();

    // Simulate initial activity
    doc.dispatch("mousemove");

    // Advance 5 seconds while visible and active
    vi.advanceTimersByTime(5000);

    expect(tracker.getEngagementTimeMs()).toBe(5000);

    // Hide the tab
    doc.setVisibilityState("hidden");
    doc.dispatch("visibilitychange");

    // Advance 10 seconds while hidden
    vi.advanceTimersByTime(10000);

    // Time should not have increased
    expect(tracker.getEngagementTimeMs()).toBe(5000);

    tracker.destroy();
  });

  it("activity is detected via scroll, click, keydown, and mousemove events", () => {
    const doc = installDocument();
    const tracker = createEngagementTracker();

    // Check handlers are registered
    expect(doc.getHandlerCount("scroll")).toBeGreaterThan(0);
    expect(doc.getHandlerCount("click")).toBeGreaterThan(0);
    expect(doc.getHandlerCount("keydown")).toBeGreaterThan(0);
    expect(doc.getHandlerCount("mousemove")).toBeGreaterThan(0);

    // Each activity type should reset idle timer
    doc.dispatch("scroll");
    vi.advanceTimersByTime(1000);
    expect(tracker.getEngagementTimeMs()).toBe(1000);

    doc.dispatch("click");
    vi.advanceTimersByTime(1000);
    expect(tracker.getEngagementTimeMs()).toBe(2000);

    doc.dispatch("keydown");
    vi.advanceTimersByTime(1000);
    expect(tracker.getEngagementTimeMs()).toBe(3000);

    doc.dispatch("mousemove");
    vi.advanceTimersByTime(1000);
    expect(tracker.getEngagementTimeMs()).toBe(4000);

    tracker.destroy();
  });

  it("visibilitychange event pauses/resumes tracking correctly", () => {
    const doc = installDocument();
    const tracker = createEngagementTracker();

    doc.dispatch("mousemove");
    vi.advanceTimersByTime(2000);
    expect(tracker.getEngagementTimeMs()).toBe(2000);

    // Hide tab
    doc.setVisibilityState("hidden");
    doc.dispatch("visibilitychange");
    vi.advanceTimersByTime(5000);
    expect(tracker.getEngagementTimeMs()).toBe(2000);

    // Show tab again
    doc.setVisibilityState("visible");
    doc.dispatch("visibilitychange");
    doc.dispatch("mousemove"); // Activity resumes tracking
    vi.advanceTimersByTime(3000);
    expect(tracker.getEngagementTimeMs()).toBe(5000);

    tracker.destroy();
  });

  it("idle timeout of 30 seconds stops time accumulation", () => {
    const doc = installDocument();
    const tracker = createEngagementTracker();

    // Initial activity
    doc.dispatch("mousemove");
    vi.advanceTimersByTime(5000);
    expect(tracker.getEngagementTimeMs()).toBe(5000);

    // No activity for 30 seconds - time accumulates until idle threshold
    vi.advanceTimersByTime(30000);
    // After 30s of no activity from the last activity at t=5s,
    // we're now at t=35s, but idle started at t=35s (5s + 30s timeout)
    // So we should have accumulated from t=0 to t=35s = 35s,
    // but actually idle kicks in 30s after last activity
    // Last activity was at t=5s, so idle at t=35s means we tracked 5s + ~30s
    // Due to tick interval, accumulated time is approximately 30s (29.9s)
    // The tracker stops counting when idle, which happens ~30s after last activity
    expect(tracker.getEngagementTimeMs()).toBeGreaterThanOrEqual(29900);
    expect(tracker.getEngagementTimeMs()).toBeLessThanOrEqual(35100);

    const timeAtIdle = tracker.getEngagementTimeMs();

    // More time passes while idle - no accumulation
    vi.advanceTimersByTime(10000);
    expect(tracker.getEngagementTimeMs()).toBe(timeAtIdle);

    // Activity resumes
    doc.dispatch("mousemove");
    vi.advanceTimersByTime(5000);
    expect(tracker.getEngagementTimeMs()).toBe(timeAtIdle + 5000);

    tracker.destroy();
  });

  it("reset() clears accumulated time", () => {
    const doc = installDocument();
    const tracker = createEngagementTracker();

    doc.dispatch("mousemove");
    vi.advanceTimersByTime(5000);
    expect(tracker.getEngagementTimeMs()).toBe(5000);

    tracker.reset();
    expect(tracker.getEngagementTimeMs()).toBe(0);

    tracker.destroy();
  });

  it("destroy() removes all event listeners", () => {
    const doc = installDocument();
    const tracker = createEngagementTracker();

    // Listeners should be registered
    expect(doc.getHandlerCount("scroll")).toBeGreaterThan(0);

    tracker.destroy();

    // Listeners should be removed
    expect(doc.getHandlerCount("scroll")).toBe(0);
    expect(doc.getHandlerCount("click")).toBe(0);
    expect(doc.getHandlerCount("keydown")).toBe(0);
    expect(doc.getHandlerCount("mousemove")).toBe(0);
    expect(doc.getHandlerCount("visibilitychange")).toBe(0);
  });

  it("handles SSR gracefully (returns 0 when document undefined)", () => {
    // Remove document
    const originalDocument = globalThis.document;
    // @ts-expect-error testing undefined
    delete globalThis.document;

    const tracker = createEngagementTracker();
    expect(tracker.getEngagementTimeMs()).toBe(0);

    tracker.destroy();

    // Restore
    if (originalDocument) {
      Object.defineProperty(globalThis, "document", {
        value: originalDocument,
        configurable: true,
      });
    }
  });
});

import { describe, expect, it, vi, beforeEach, afterEach } from "vitest";

import { createScrollTracker } from "../src/scroll";

function installScrollEnvironment(options: {
  scrollTop?: number;
  scrollHeight?: number;
  clientHeight?: number;
}) {
  const handlers: Map<string, Set<EventListener>> = new Map();

  let scrollTop = options.scrollTop ?? 0;
  const scrollHeight = options.scrollHeight ?? 2000;
  const clientHeight = options.clientHeight ?? 800;

  Object.defineProperty(globalThis, "window", {
    value: {
      scrollY: scrollTop,
      innerHeight: clientHeight,
      addEventListener(type: string, handler: EventListener, options?: AddEventListenerOptions | boolean) {
        if (!handlers.has(type)) handlers.set(type, new Set());
        handlers.get(type)!.add(handler);
      },
      removeEventListener(type: string, handler: EventListener) {
        handlers.get(type)?.delete(handler);
      },
    },
    configurable: true,
  });

  Object.defineProperty(globalThis, "document", {
    value: {
      documentElement: {
        get scrollHeight() {
          return scrollHeight;
        },
        get clientHeight() {
          return clientHeight;
        },
      },
      body: {
        get scrollHeight() {
          return scrollHeight;
        },
      },
    },
    configurable: true,
  });

  return {
    setScrollPosition(position: number) {
      scrollTop = position;
      (globalThis.window as any).scrollY = position;
    },
    dispatch(type: string) {
      const event = { type } as Event;
      handlers.get(type)?.forEach((h) => h(event));
    },
    getHandlerCount(type: string) {
      return handlers.get(type)?.size ?? 0;
    },
  };
}

describe("Task 1.1.B - Scroll Depth Tracker", () => {
  it("createScrollTracker returns object with getMaxScrollDepth, reset, and destroy methods", () => {
    installScrollEnvironment({});
    const tracker = createScrollTracker();

    expect(typeof tracker.getMaxScrollDepth).toBe("function");
    expect(typeof tracker.reset).toBe("function");
    expect(typeof tracker.destroy).toBe("function");

    tracker.destroy();
  });

  it("scroll depth calculated as scrollTop / (docHeight - viewportHeight) * 100", () => {
    // Page height: 2000px, viewport: 800px, scrollable: 1200px
    const env = installScrollEnvironment({
      scrollHeight: 2000,
      clientHeight: 800,
    });
    const tracker = createScrollTracker();

    // Scroll to 600px (50% of scrollable area)
    env.setScrollPosition(600);
    env.dispatch("scroll");

    expect(tracker.getMaxScrollDepth()).toBe(50);

    // Scroll to 1200px (100% of scrollable area)
    env.setScrollPosition(1200);
    env.dispatch("scroll");

    expect(tracker.getMaxScrollDepth()).toBe(100);

    tracker.destroy();
  });

  it("returns 100% if page fits entirely in viewport (no scrollbar)", () => {
    // Page height: 500px, viewport: 800px (no scrolling possible)
    installScrollEnvironment({
      scrollHeight: 500,
      clientHeight: 800,
    });
    const tracker = createScrollTracker();

    // Should immediately be 100% since no scrolling is needed
    expect(tracker.getMaxScrollDepth()).toBe(100);

    tracker.destroy();
  });

  it("tracks maximum depth reached, not current position", () => {
    const env = installScrollEnvironment({
      scrollHeight: 2000,
      clientHeight: 800,
    });
    const tracker = createScrollTracker();

    // Scroll to 75%
    env.setScrollPosition(900);
    env.dispatch("scroll");
    expect(tracker.getMaxScrollDepth()).toBe(75);

    // Scroll back to 25%
    env.setScrollPosition(300);
    env.dispatch("scroll");

    // Should still report 75% (maximum reached)
    expect(tracker.getMaxScrollDepth()).toBe(75);

    // Scroll to 100%
    env.setScrollPosition(1200);
    env.dispatch("scroll");
    expect(tracker.getMaxScrollDepth()).toBe(100);

    tracker.destroy();
  });

  it("uses passive scroll event listener for performance", () => {
    const addEventListenerSpy = vi.fn();

    Object.defineProperty(globalThis, "window", {
      value: {
        scrollY: 0,
        innerHeight: 800,
        addEventListener: addEventListenerSpy,
        removeEventListener: vi.fn(),
      },
      configurable: true,
    });

    Object.defineProperty(globalThis, "document", {
      value: {
        documentElement: {
          scrollHeight: 2000,
          clientHeight: 800,
        },
        body: {
          scrollHeight: 2000,
        },
      },
      configurable: true,
    });

    const tracker = createScrollTracker();

    expect(addEventListenerSpy).toHaveBeenCalledWith(
      "scroll",
      expect.any(Function),
      expect.objectContaining({ passive: true })
    );

    tracker.destroy();
  });

  it("reset() clears maximum scroll depth", () => {
    const env = installScrollEnvironment({
      scrollHeight: 2000,
      clientHeight: 800,
    });
    const tracker = createScrollTracker();

    env.setScrollPosition(600);
    env.dispatch("scroll");
    expect(tracker.getMaxScrollDepth()).toBe(50);

    tracker.reset();
    expect(tracker.getMaxScrollDepth()).toBe(0);

    tracker.destroy();
  });

  it("destroy() removes scroll event listener", () => {
    const env = installScrollEnvironment({});
    const tracker = createScrollTracker();

    expect(env.getHandlerCount("scroll")).toBeGreaterThan(0);

    tracker.destroy();

    expect(env.getHandlerCount("scroll")).toBe(0);
  });

  it("handles SSR gracefully (returns 0 when window undefined)", () => {
    const originalWindow = globalThis.window;
    // @ts-expect-error testing undefined
    delete globalThis.window;

    const tracker = createScrollTracker();
    expect(tracker.getMaxScrollDepth()).toBe(0);

    tracker.destroy();

    if (originalWindow) {
      Object.defineProperty(globalThis, "window", {
        value: originalWindow,
        configurable: true,
      });
    }
  });
});

import { describe, expect, it, beforeEach, afterEach } from "vitest";

import { captureUTMParams, UTMParams } from "../src/utm";

function installWindow(url: string) {
  Object.defineProperty(globalThis, "window", {
    value: {
      location: {
        href: url,
        search: new URL(url).search,
      },
    },
    configurable: true,
  });
}

describe("Task 1.1.D - UTM Parameter Capture", () => {
  afterEach(() => {
    // @ts-expect-error cleanup
    delete globalThis.window;
  });

  it("captureUTMParams returns object with optional utm_source, utm_medium, utm_campaign, utm_term, utm_content", () => {
    installWindow("https://example.com/?utm_source=google&utm_medium=cpc&utm_campaign=summer&utm_term=shoes&utm_content=banner");

    const result = captureUTMParams();

    expect(result.utm_source).toBe("google");
    expect(result.utm_medium).toBe("cpc");
    expect(result.utm_campaign).toBe("summer");
    expect(result.utm_term).toBe("shoes");
    expect(result.utm_content).toBe("banner");
  });

  it("parses parameters from current URL query string", () => {
    installWindow("https://example.com/page?utm_source=facebook&utm_medium=social");

    const result = captureUTMParams();

    expect(result.utm_source).toBe("facebook");
    expect(result.utm_medium).toBe("social");
    expect(result.utm_campaign).toBeUndefined();
  });

  it("truncates each value to 100 characters maximum", () => {
    const longValue = "a".repeat(150);
    installWindow(`https://example.com/?utm_source=${longValue}&utm_medium=short`);

    const result = captureUTMParams();

    expect(result.utm_source).toBe("a".repeat(100));
    expect(result.utm_source?.length).toBe(100);
    expect(result.utm_medium).toBe("short");
  });

  it("returns empty object if no UTM params present", () => {
    installWindow("https://example.com/page?other=value&foo=bar");

    const result = captureUTMParams();

    expect(result).toEqual({});
    expect(result.utm_source).toBeUndefined();
    expect(result.utm_medium).toBeUndefined();
    expect(result.utm_campaign).toBeUndefined();
    expect(result.utm_term).toBeUndefined();
    expect(result.utm_content).toBeUndefined();
  });

  it("handles SSR gracefully (returns empty object when window undefined)", () => {
    // Ensure window is not defined
    // @ts-expect-error testing undefined
    delete globalThis.window;

    const result = captureUTMParams();

    expect(result).toEqual({});
  });

  it("handles URL without query string", () => {
    installWindow("https://example.com/page");

    const result = captureUTMParams();

    expect(result).toEqual({});
  });

  it("handles partial UTM params", () => {
    installWindow("https://example.com/?utm_source=newsletter");

    const result = captureUTMParams();

    expect(result.utm_source).toBe("newsletter");
    expect(result.utm_medium).toBeUndefined();
    expect(result.utm_campaign).toBeUndefined();
  });

  it("decodes URL-encoded values", () => {
    installWindow("https://example.com/?utm_source=google&utm_campaign=summer%20sale%202025");

    const result = captureUTMParams();

    expect(result.utm_campaign).toBe("summer sale 2025");
  });

  it("handles empty UTM values gracefully", () => {
    installWindow("https://example.com/?utm_source=&utm_medium=cpc");

    const result = captureUTMParams();

    // Empty string is falsy, so it should be excluded
    expect(result.utm_source).toBeUndefined();
    expect(result.utm_medium).toBe("cpc");
  });
});

import { describe, expect, it, vi, beforeEach } from "vitest";

import { getOrCreateVisitorId } from "../src/visitor";

function installCookieDocument(options: { isHttps?: boolean } = {}) {
  const jar = new Map<string, string>();
  const isHttps = options.isHttps ?? true;

  Object.defineProperty(globalThis, "document", {
    value: {
      get cookie() {
        return Array.from(jar.entries())
          .map(([name, value]) => `${name}=${value}`)
          .join("; ");
      },
      set cookie(value: string) {
        const [pair] = value.split(";");
        const [name, cookieValue] = pair.split("=");
        jar.set(name.trim(), (cookieValue ?? "").trim());
      },
    },
    configurable: true,
  });

  Object.defineProperty(globalThis, "location", {
    value: {
      protocol: isHttps ? "https:" : "http:",
    },
    configurable: true,
  });

  return {
    get(name: string) {
      return jar.get(name);
    },
    set(name: string, value: string) {
      jar.set(name, value);
    },
    getRawCookie() {
      return (globalThis.document as any).cookie;
    },
    getCookieString(name: string): string | undefined {
      // Get the full cookie string that was set (for verifying attributes)
      return jar.get(name);
    },
  };
}

describe("Task 1.1.C - Visitor ID Manager", () => {
  beforeEach(() => {
    // Reset any existing document/location
    // @ts-expect-error testing cleanup
    delete globalThis.document;
    // @ts-expect-error testing cleanup
    delete globalThis.location;
  });

  it("getOrCreateVisitorId returns { visitorId: string; isReturning: boolean }", () => {
    const cookieJar = installCookieDocument();
    const uuid = "11111111-1111-4111-8111-111111111111";

    vi.spyOn(globalThis.crypto, "randomUUID").mockReturnValue(uuid);

    const result = getOrCreateVisitorId();

    expect(result).toHaveProperty("visitorId");
    expect(result).toHaveProperty("isReturning");
    expect(typeof result.visitorId).toBe("string");
    expect(typeof result.isReturning).toBe("boolean");
  });

  it("creates tally_vid cookie with UUID v4 value on first visit", () => {
    const cookieJar = installCookieDocument();
    const uuid = "22222222-2222-4222-8222-222222222222";

    vi.spyOn(globalThis.crypto, "randomUUID").mockReturnValue(uuid);

    const result = getOrCreateVisitorId();

    expect(result.visitorId).toBe(uuid);
    expect(result.isReturning).toBe(false);
    expect(cookieJar.get("tally_vid")).toBe(uuid);
  });

  it("cookie has 1-year max-age, path=/, SameSite=Lax, Secure on HTTPS", () => {
    // We need to capture the full cookie string that was set
    let setCookieString = "";

    Object.defineProperty(globalThis, "document", {
      value: {
        _cookie: "",
        get cookie() {
          return this._cookie;
        },
        set cookie(value: string) {
          setCookieString = value;
          const [pair] = value.split(";");
          const [name, cookieValue] = pair.split("=");
          this._cookie = `${name}=${cookieValue}`;
        },
      },
      configurable: true,
    });

    Object.defineProperty(globalThis, "location", {
      value: {
        protocol: "https:",
      },
      configurable: true,
    });

    const uuid = "33333333-3333-4333-8333-333333333333";
    vi.spyOn(globalThis.crypto, "randomUUID").mockReturnValue(uuid);

    getOrCreateVisitorId();

    // Verify cookie attributes
    expect(setCookieString).toContain("tally_vid=" + uuid);
    expect(setCookieString).toContain("max-age=31536000"); // 1 year in seconds
    expect(setCookieString).toContain("path=/");
    expect(setCookieString.toLowerCase()).toContain("samesite=lax");
    expect(setCookieString.toLowerCase()).toContain("secure");
  });

  it("does not include Secure on HTTP", () => {
    let setCookieString = "";

    Object.defineProperty(globalThis, "document", {
      value: {
        _cookie: "",
        get cookie() {
          return this._cookie;
        },
        set cookie(value: string) {
          setCookieString = value;
          const [pair] = value.split(";");
          const [name, cookieValue] = pair.split("=");
          this._cookie = `${name}=${cookieValue}`;
        },
      },
      configurable: true,
    });

    Object.defineProperty(globalThis, "location", {
      value: {
        protocol: "http:",
      },
      configurable: true,
    });

    const uuid = "44444444-4444-4444-8444-444444444444";
    vi.spyOn(globalThis.crypto, "randomUUID").mockReturnValue(uuid);

    getOrCreateVisitorId();

    expect(setCookieString.toLowerCase()).not.toContain("secure");
  });

  it("returns isReturning: true when cookie already exists", () => {
    const cookieJar = installCookieDocument();
    const existingId = "55555555-5555-4555-8555-555555555555";

    // Pre-set the cookie
    cookieJar.set("tally_vid", existingId);

    const result = getOrCreateVisitorId();

    expect(result.visitorId).toBe(existingId);
    expect(result.isReturning).toBe(true);
  });

  it("handles SSR gracefully (returns null when document undefined)", () => {
    // Ensure document is not defined
    // @ts-expect-error testing undefined
    delete globalThis.document;

    const result = getOrCreateVisitorId();

    expect(result).toBeNull();
  });

  it("preserves existing visitor ID across multiple calls", () => {
    const cookieJar = installCookieDocument();
    const uuid = "66666666-6666-4666-8666-666666666666";

    const spy = vi.spyOn(globalThis.crypto, "randomUUID").mockReturnValue(uuid);

    const result1 = getOrCreateVisitorId();
    const result2 = getOrCreateVisitorId();

    expect(result1.visitorId).toBe(uuid);
    expect(result1.isReturning).toBe(false);

    expect(result2.visitorId).toBe(uuid);
    expect(result2.isReturning).toBe(true);

    // randomUUID should only be called once (for the first visit)
    expect(spy).toHaveBeenCalledTimes(1);
  });
});
